func solve(nums []int64, k int64) int64 {
    n := len(nums)
    prefixMod := make([]int64, n+1)
    modCounts := make(map[int64]int64)
    modCounts[0] = 1

    totalSum := int64(0)
    for i := 0; i < n; i++ {
        totalSum += nums[i]
        mod := (totalSum % k + k) % k
        prefixMod[i+1] = mod
        modCounts[mod] += 1
    }

    minSum := int64(0)
    for i := 0; i < n; i++ {
        currentMod := prefixMod[i]
        if modCounts[currentMod] > 0 {
            minSum += nums[i]
            modCounts[currentMod] -= 1
        }
    }

    return minSum
}
